import React, {useMemo, useRef} from 'react';
import './styles.scss';
import {useLocation, useNavigate} from 'react-router-dom';
import {type IMenuItem} from '@lmb-it/kitsconcerto-types';
import {Button, Center, Flex, Text} from "../../_compat";
import {Menu as PrimeMenu} from 'primereact/menu';
import {Avatar} from "primereact/avatar";
import {NavList} from "./Nav";
import {useKitsConcerto, useLanguage} from "../../_compat";
import {ResponsiveElement} from "../../factory";
import type {SidebarProps} from "primereact/sidebar";

export interface ISidebarMenuProps {
    placement: 'rtl' | 'ltr';
    routes: IMenuItem[];
    visible: boolean;
    setVisible: (visible: boolean) => void;
}

const SidebarMenu = ({visible, setVisible, placement, routes}:ISidebarMenuProps) => {
    const btnRef = useRef(null);



    const {logo, menuItems, mq} = useKitsConcerto();
    const {t} = useLanguage();
    const navigate = useNavigate();
    const openMenu = useRef<PrimeMenu | null>(null);
    const {pathname} = useLocation();
    const currentRoute = pathname.replace(/^\/|\/$/g, '');


    const FooterMenu = () => {
        return (
            <Flex alignItems={'center'}
                  className={`menu`}
                  onClick={(event) => openMenu.current?.toggle(event)}
                  cursor={'pointer'}
                  ml={'3rem'}
            >
                <PrimeMenu model={menuItems} popup ref={openMenu} id="popup_menu_right"
                           popupAlignment="right"/>
                <Avatar icon="pi pi-user" size={'normal'} shape={'circle'}/>
                <Text>{t('profile')}</Text>
                <Button
                    severity={'secondary'}
                    icon="pi pi-angle-up"
                    className="mr-2"
                    // text={true}
                    aria-controls="popup_menu_right"
                    aria-haspopup
                />
            </Flex>
        )
    }

    const contents = useMemo(() => (
            <Flex className="min-h-screen relative lg:static">
                <div id="app-sidebar-2"
                     className="h-screen lg:block flex-shrink-0 absolute lg:static left-0 top-0 z-1 surface-border select-none"
                     style={{width: '100%'}}>
                    <div className="flex flex-column h-full">
                        {!mq.isSmall && <div
                            className="flex align-items-center justify-content-between px-4 pt-3 flex-shrink-0 w-12 lg:w-12 sm:w-4">
                                    <span className="inline-flex align-items-center gap-2">
                                        {logo && <Center w={'100%'} overflow={'hidden'}>{logo}</Center>}
                                    </span>

                        </div>}
                        <div className={mq.isSmall?'':'overflow-y-auto'}>
                            <Flex flexDirection={"column"} justifyContent={'space-between'} h={"auto"}>
                                <NavList items={routes} currentRoute={currentRoute}/>
                                {/*{isSenior && <Flex justifyContent={"center"}>*/}
                                {/*    <LanguageSwitcher/>*/}
                                {/*</Flex>}*/}
                            </Flex>
                        </div>
                    </div>
                </div>

            </Flex>
        ),
        [logo, routes, currentRoute, mq.isSmall]
    );

    return (
        <Flex w={'full'}
              position={'relative'}
              flexDirection={'column'}
              shadow={4}
              className={'nav-container'}
              style={{direction: placement}}>
            {!mq.isSmall && contents}
            {mq.isSmall && <ResponsiveElement as={'Sidebar'}
                                              nativeProps={{
                                                  visible,
                                                  header: () => {
                                                      return <Flex>
                                                          <Center>{logo}</Center>
                                                          <Flex position={'absolute'} top={10} right={10}>
                                                              <Button type="button" onClick={() => setVisible(false)}
                                                                      icon="pi pi-times" rounded outlined
                                                                      className="h-2rem w-2rem"></Button>
                                                          </Flex>
                                                      </Flex>
                                                  },
                                                  onHide: () => setVisible(false),
                                                  showCloseIcon: false,
                                                  maskStyle:{
                                                      padding:0
                                                  }, style:{padding:0}
                                              } as SidebarProps}
            cssProps={{
                width:['100%','50%','40%']
            }}>
                {contents}
            </ResponsiveElement>}
        </Flex>
    );
};

export default SidebarMenu;
